// ============ LAYER 1: ENTITY (lib/domain/entities/user.dart) ============
// Pure business object. No Flutter, no JSON, no annotations.
class User {
  const User({required this.id, required this.email, required this.name});
  final int id;
  final String email;
  final String name;

  // Business rule that BELONGS to User.
  bool get hasValidEmail => email.contains('@') && email.contains('.');
}

// ============ LAYER 2: USE CASE (lib/domain/usecases/register_user.dart) ==
// Application-specific business rule. Depends only on entities + repository INTERFACE.
class RegisterUser {
  RegisterUser(this._repo);
  final UserRepository _repo;   // interface — not the concrete impl

  Future<User> call({required String email, required String name}) async {
    // Validation lives here — not in the widget, not in the network layer.
    if (name.isEmpty) throw ArgumentError('name required');
    final draft = User(id: 0, email: email, name: name);
    if (!draft.hasValidEmail) throw ArgumentError('invalid email');

    return await _repo.create(draft);
  }
}

// ============ LAYER 2: INTERFACE (lib/domain/repositories/user_repository.dart) =
// The USE CASE declares WHAT it needs. The DATA layer provides HOW.
abstract class UserRepository {
  Future<User> create(User draft);
  Future<User?> getById(int id);
}

// ============ LAYER 3: DATA (lib/data/repositories/user_repository_impl.dart) =
// Implements the interface. Depends on Retrofit + Hive.
import 'package:dio/dio.dart';
import 'package:hive/hive.dart';

class UserRepositoryImpl implements UserRepository {
  UserRepositoryImpl(this._api, this._cache);
  final Dio _api;
  final Box<Map> _cache;

  @override
  Future<User> create(User draft) async {
    final resp = await _api.post('/users', data: {
      'email': draft.email, 'name': draft.name,
    });
    final dto = UserDto.fromJson(resp.data);
    await _cache.put('user_${dto.id}', resp.data);
    return dto.toEntity();
  }

  @override
  Future<User?> getById(int id) async {
    // Cache-first, network fallback.
    final cached = _cache.get('user_$id');
    if (cached != null) return UserDto.fromJson(cached).toEntity();
    final resp = await _api.get('/users/$id');
    return UserDto.fromJson(resp.data).toEntity();
  }
}

// ============ LAYER 4: PRESENTATION (lib/presentation/viewmodels/login_vm.dart) =
import 'package:flutter/foundation.dart';

class LoginViewModel extends ChangeNotifier {
  LoginViewModel(this._registerUser);
  final RegisterUser _registerUser;   // use case — not the repository!

  bool loading = false;
  String? error;

  Future<void> submit(String email, String name) async {
    loading = true; error = null; notifyListeners();
    try {
      await _registerUser(email: email, name: name);
    } catch (e) {
      error = e.toString();
    } finally {
      loading = false; notifyListeners();
    }
  }
}

// ============ LAYER 4: WIRING (lib/main.dart) ============
// DI wires all four layers together. Only main.dart imports everything.
void main() {
  final api = Dio();
  final cache = Hive.box<Map>('users');
  final repo = UserRepositoryImpl(api, cache);        // Layer 3
  final registerUser = RegisterUser(repo);            // Layer 2
  final vm = LoginViewModel(registerUser);            // Layer 4

  runApp(MyApp(vm: vm));
}

// Try grep -R 'import.*flutter' lib/domain/ — should return NOTHING.
// That's the litmus test.
